// BUG FIX: Este nodo ahora lanza AMBAS peticiones en paralelo
// y usa un merge interno para deduplicar correctamente.
// Recibe la respuesta del AI Trend Hunter y TAMBIÉN hace el GET a Supabase
// antes de comparar.

const source = $input.first().json;
let rawText = '';
if (typeof source?.choices?.[0]?.message?.content === 'string') {
  rawText = source.choices[0].message.content;
} else if (Array.isArray(source?.choices?.[0]?.message?.content)) {
  rawText = source.choices[0].message.content.map(p => p?.text || '').join('');
} else {
  rawText = JSON.stringify(source);
}
rawText = rawText.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let topics;
try { topics = JSON.parse(rawText); } catch(e) {
  const m = rawText.match(/\[([\s\S]+?)\]/);
  if (!m) throw new Error('No se pudo parsear array de temas: ' + rawText.substring(0, 500));
  try { topics = JSON.parse('[' + m[1] + ']'); } catch(e2) {
    throw new Error('Parse fallido incluso con extracción manual: ' + rawText.substring(0, 500));
  }
}
if (!Array.isArray(topics) || topics.length === 0) throw new Error('El AI no devolvió temas válidos.');
const result = topics.slice(0, 3).map(t => ({ json: { title: (t.title || '').trim(), keywords: (t.keywords || '').trim(), category_slug: (t.category_slug || 'ia').trim() } }));
console.log('Temas parseados del AI:', result.map(r => r.json.title));
return result;

// BUG FIX PRINCIPAL:
// Antes: recibía solo 1 input (Supabase), perdía los temas del AI.
// Ahora: recibe el Merge con AMBOS inputs y compara correctamente.

const allItems = $input.all();

// Separar los temas del AI (tienen title + keywords) vs los de Supabase (solo title)
const aiTopics = allItems.filter(i => i.json.keywords !== undefined);
const supabaseItems = allItems.filter(i => i.json.keywords === undefined);

console.log(`Items del AI: ${aiTopics.length}, Items de Supabase: ${supabaseItems.length}`);

// Construir set de títulos existentes en Supabase (todos los status)
const existingTitles = new Set();
for (const item of supabaseItems) {
  // Supabase devuelve array directamente o dentro de .data
  const raw = item.json;
  const arr = Array.isArray(raw) ? raw : (raw?.data || [raw]);
  for (const t of arr) {
    if (t?.title) existingTitles.add(t.title.toLowerCase().trim());
  }
}

console.log(`Títulos existentes en Supabase: ${existingTitles.size}`, [...existingTitles]);

// Filtrar temas del AI que NO estén en Supabase
const newTopics = aiTopics.filter(item => {
  const t = (item.json.title || '').toLowerCase().trim();
  const isDup = existingTitles.has(t);
  if (isDup) console.log(`Duplicado detectado, saltando: "${item.json.title}"`);
  return t.length > 5 && !isDup;
});

if (newTopics.length === 0) {
  console.log('Todos los temas propuestos ya existen. No se insertarán duplicados.');
  return [{ json: { skipped: true, message: 'No hay temas nuevos para insertar.' } }];
}

console.log(`Temas nuevos a insertar: ${newTopics.length}`, newTopics.map(t => t.json.title));
return newTopics.map(i => ({ json: i.json }));

// Verificar que el INSERT fue exitoso antes de continuar
const res = $input.first().json;
const inserted = Array.isArray(res) ? res[0] : res;
if (!inserted?.id) {
  console.warn('INSERT no devolvió id, respuesta:', JSON.stringify(res));
} else {
  console.log(`✓ Tema insertado correctamente: id=${inserted.id}, title="${inserted.title}"`);
}
return [{ json: inserted || res }];

const raw = $input.first().json;
console.log('GET Temas Pendientes respuesta raw:', JSON.stringify(raw));

let topics = [];
if (Array.isArray(raw)) {
  topics = raw;
} else if (raw?.data && Array.isArray(raw.data)) {
  topics = raw.data;
} else if (raw?.id) {
  topics = [raw];
}

console.log(`Temas pendientes encontrados: ${topics.length}`);

if (topics.length === 0) {
  throw new Error(
    'No hay temas pendientes en blog_topics. ' +
    'Respuesta cruda: ' + JSON.stringify(raw)
  );
}

return topics.map(t => ({
  json: {
    topic_id: t.id,
    title: t.title,
    keywords: t.keywords || '',
    category_slug: t.category_slug || 'ia'
  }
}));

const raw = $input.first()?.json?.content?.parts?.[0]?.text ||
  $input.first()?.json?.choices?.[0]?.message?.content ||
  $input.first()?.json?.text || '';
const text = raw.replace(/\r/g, '').trim();
function cleanPrompt(v) {
  return (v || '').replace(/^["'`]+|["'`]+$/g,'').replace(/\n+/g,' ').replace(/\s+/g,' ').trim();
}
function extractLabeled(label, nextLabels=[]) {
  const next = nextLabels.length ? `(?=\\(${nextLabels.join('|')}\\)|$)` : '$';
  const rx = new RegExp(`\\(${label}\\)\\s*([\\s\\S]+?)${next}`,'i');
  return cleanPrompt(text.match(rx)?.[1] || '');
}
let pA = extractLabeled('A',['B','C']);
let pB = extractLabeled('B',['C']);
let pC = extractLabeled('C',[]);
const bullets = text.split('\n').map(l=>cleanPrompt(l.replace(/^[-*•\d.)\s]+/,''))).filter(Boolean);
if (!pA && bullets[0]) pA = bullets[0];
if (!pB && bullets[1]) pB = bullets[1];
if (!pC && bullets[2]) pC = bullets[2];
if (pA && !pB) pB = `${pA}, editorial lifestyle scene, fashion ecommerce context, different composition`;
if (pA && !pC) pC = `${pA}, secondary supporting visual, alternate angle, AI virtual try-on detail`;
if (!pA) throw new Error('No se pudieron extraer los prompts. Texto: ' + text.substring(0,500));
const topicData = $('Loop Temas Pendientes').item.json;
return [
  { json: { prompt: pA, tipo: 'destacada', orden: 1, ...topicData } },
  { json: { prompt: pB, tipo: 'body1', orden: 2, ...topicData } },
  { json: { prompt: pC, tipo: 'body2', orden: 3, ...topicData } }
];

const source = $input.item.json;
const loopData = $('Loop Imágenes').item.json;
let url = '';
if (source?.choices?.[0]?.message?.content) {
  const content = source.choices[0].message.content;
  const m = content.match(/https:\/\/\S+/);
  url = m ? m[0] : content;
} else if (source?.imageUrl) {
  url = source.imageUrl;
} else if (source?.data?.[0]?.url) {
  url = source.data[0].url;
} else {
  url = JSON.stringify(source);
}
return [{ json: { ...loopData, imageUrl: url } }];

const response = $input.item.json;
const currentItem = $('Loop Imágenes').item.json;
const token = '***REMOVED-SECRET***';
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
async function getPrediction(url) {
  const res = await fetch(url, { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' } });
  if (!res.ok) throw new Error(`Replicate lookup failed (${res.status}): ${await res.text()}`);
  return await res.json();
}
async function resolvePrediction(pred) {
  let cur = pred;
  for (let i = 0; i < 30; i++) {
    if (cur?.error) throw new Error(`Replicate error en ${currentItem.tipo}: ${cur.error}`);
    if (cur?.status === 'failed' || cur?.status === 'canceled') throw new Error(`Replicate ${cur.status}. ID: ${cur.id}`);
    if (cur?.status === 'succeeded' && cur?.output) {
      const imageUrl = Array.isArray(cur.output) ? cur.output[0] : cur.output;
      return [{ json: { ...currentItem, imageUrl, predictionId: cur.id } }];
    }
    const pollUrl = cur?.urls?.get;
    if (!pollUrl) throw new Error(`Sin output ni poll URL. Status: ${cur?.status || 'unknown'}`);
    await sleep(4000);
    cur = await getPrediction(pollUrl);
  }
  throw new Error(`Replicate timeout para ${currentItem.tipo}`);
}
return await resolvePrediction(response);

const item = $input.item;
const tipo = item.json.tipo || 'imagen';
if (item.binary?.data) {
  item.binary.data.fileName = `${tipo}.png`;
  item.binary.data.mimeType = 'image/png';
}
return { json: { ...item.json, tipo }, binary: item.binary };

const rawItems = $input.all();
const source = rawItems.length === 1 && Array.isArray(rawItems[0].json?.data) ? rawItems[0].json.data : rawItems.map(i => i.json);
const enlacesBlogs = source.slice(0, 8).map(post => ({ titulo: post.title, url: `https://lookitry.com/blog/${post.slug}` }));
return [{ json: { enlacesBlogs } }];

const allItems = $input.all();
const topicItem = allItems.find(i => i.json.topic_id && i.json.title);
const imgItem = allItems.find(i => i.json.imagen_destacada);
const linksItem = allItems.find(i => Array.isArray(i.json.enlacesBlogs));
if (!topicItem) throw new Error('No se encontraron datos del tema en el merge.');
if (!imgItem) throw new Error('No se encontraron datos de imágenes en el merge.');
const d = {
  ...topicItem.json,
  imagen_destacada: imgItem.json.imagen_destacada,
  imagen_destacada_url: imgItem.json.imagen_destacada?.url || '',
  imagen_body1_url: imgItem.json.imagen_body1?.url || '',
  imagen_body2_url: imgItem.json.imagen_body2?.url || '',
  enlacesBlogs: linksItem?.json?.enlacesBlogs || []
};
return [{ json: d }];

const source = $input.item.json;
let rawText = '';
if (typeof source?.choices?.[0]?.message?.content === 'string') {
  rawText = source.choices[0].message.content;
} else if (Array.isArray(source?.choices?.[0]?.message?.content)) {
  rawText = source.choices[0].message.content.map(p => typeof p === 'string' ? p : p?.text || '').join('');
} else if (source?.content?.parts?.[0]?.text) {
  rawText = source.content.parts[0].text;
} else {
  rawText = JSON.stringify(source);
}
rawText = rawText.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
let parsed = null;
try { parsed = JSON.parse(rawText); } catch(_) {}
if (!parsed) {
  function extractFirstJson(text) {
    const start = text.indexOf('{');
    if (start === -1) return null;
    let depth=0, inStr=false, esc=false;
    for (let i=start;i<text.length;i++) {
      const ch=text[i];
      if(esc){esc=false;continue;}
      if(ch==='\\'){esc=true;continue;}
      if(ch==='"'){inStr=!inStr;continue;}
      if(inStr)continue;
      if(ch==='{')depth++;
      if(ch==='}')depth--;
      if(depth===0)return text.slice(start,i+1);
    }
    return null;
  }
  const jsonStr = extractFirstJson(rawText);
  if (!jsonStr) throw new Error('No JSON válido. Respuesta: '+rawText.substring(0,700));
  parsed = JSON.parse(jsonStr);
}
const missing=['title','excerpt','content'].filter(f=>!parsed[f]);
if(missing.length>0) throw new Error(`Campos faltantes: ${missing.join(', ')}`);
return [{ json: parsed }];

const article = $input.first().json;
let ctx = {};
try { ctx = $('Preparar Contexto Editorial').first().json || {}; } catch(e) {}
const rawTags = article.tags || article.Tags || ctx.Tags || [];
const tagsArray = Array.isArray(rawTags) ? rawTags.map(t=>String(t||'').trim()).filter(Boolean) : String(rawTags||'').split(',').map(t=>t.trim()).filter(Boolean);
const categorySlug = String(article.category_slug || ctx.category_slug || 'ia').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'') || 'ia';
const excerpt = (article.excerpt || '').substring(0,157) + ((article.excerpt||'').length > 157 ? '...' : '');
const meta_description = (article.meta_description || article.excerpt || '').substring(0,157) + '...';
const wpBody = {
  title: article.title,
  excerpt,
  content: article.content,
  status: 'published',
  category_slug: categorySlug,
  tags: tagsArray,
  featured_image: ctx.imagen_destacada_url || '',
  meta_description,
  topic_id: ctx.topic_id || ''
};
return [{ json: { wpBody, ...ctx, tags: tagsArray, category_slug: categorySlug, title: article.title, excerpt, content: article.content, meta_description } }];

const topicId = $('Preparar Contexto Editorial').first().json?.topic_id || 'desconocido';
const title = $('Preparar Contexto Editorial').first().json?.title || 'desconocido';
const respuesta = $input.first().json;
console.log(`ERROR AL PUBLICAR: topic_id=${topicId}, title=${title}`);
console.log('Respuesta Lookitry:', JSON.stringify(respuesta));
return [{ json: { error: true, topic_id: topicId, title, response: respuesta, timestamp: new Date().toISOString() } }];

const topicId = $('Preparar Contexto Editorial').first().json?.topic_id || 'N/A';
const title = $('Preparar Contexto Editorial').first().json?.title || 'N/A';
console.log(`✓ Artículo publicado. topic_id=${topicId}, title=${title}`);
return [{ json: { success: true, topic_id: topicId, title, timestamp: new Date().toISOString() } }];
